#include <iostream>
#include <vector>

struct ListNode {
    int val;
    ListNode *next;

    ListNode(int val) : val(val), next(NULL) {}
};

bool mergeTwoLists(ListNode* list1, ListNode* list2) {
    if (list2 == NULL) return list1;
    if (list1 == NULL) return list2;

    ListNode dummy;
    ListNode* curr = &dummy;

    while (list1 && list2) {
        if (list1->val < list2->val) {
            curr->next = list1;
            list1 = list1->next;
        } else {
            curr->next = list2;
            list2 = list2->next;
        }
        curr = curr->next;
    }
    curr->next = list1 ? list1 : list2;
    return dummy.next;
}

int main() {

    // Read input from cin
    std::vector<int> nums1;
    for (int i = 0; i < 3; ++i) {
        int a;
        std::cin >> a;
        nums1.push_back(a);
    }
    ListNode* list1 = new ListNode(nums1[0]);
    ListNode* curr = list1;
    for (int i = 1; i < 3; ++i) {
        curr->next = new ListNode(nums1[i]);
        curr = curr->next;
    }

    std::vector<int> nums2;
    for (int i = 0; i < 3; ++i) {
        int a;
        std::cin >> a;
        nums2.push_back(a);
    }
    ListNode* list2 = new ListNode(nums2[0]);
    curr = list2;
    for (int i = 1; i < 3; ++i) {
        curr->next = new ListNode(nums2[i]);
        curr = curr->next;
    }

    // Call the function
    ListNode* ans = mergeTwoLists(list1, list2);

    // Print the output
    while (ans) {
        std::cout << ans->val << ' -> ';
        ans = ans->next;
    }
    std::cout << 'None';

    return 0;
}
